require('./http')(q).then(e=>{
  console.log(e);

  let r={};
  let j=JSON.parse(e);
  // console.log('-',j);

  if(j && Array.isArray(j)){
    let s=j[0];
    if(s&&Array.isArray(s)){
      r.s=s.map(e=>{return {'t':e[0],'s':e[1]}});
    }
    let sl=j[2];
    if(typeof sl==='string') {
      r.sl=sl;
    }
  }

  console.log(r);
});


